 59→        effect: "deny",
 60→        priority: 100,
 61→      }],
 62→    });
 63→    await activatePolicy(surreal, policyId, adminId, workspace.workspaceId);
 64→
 65→    // And an agent identity that submits an intent to deploy
 66→    const agentId = await createTestIdentity(surreal, "coding-agent", "agent", workspace.workspaceId);
 67→
