 30→describe("Milestone 1: Policy Schema Enforcement (US-1)", () => {
 31→  // ---------------------------------------------------------------------------
 32→  // US-1: Policy created with all required fields
 33→  // AC-1 happy path
 34→  // ---------------------------------------------------------------------------
 35→  it("creates a policy record with title, rules, selector, and flags", async () => {
