150→describe("Milestone 1: Policy Lifecycle Management (US-2)", () => {
151→  // ---------------------------------------------------------------------------
152→  // US-2: Draft -> Active transition with audit event
153→  // AC-2 happy path
154→  // ---------------------------------------------------------------------------
155→  it("activates a draft policy and creates graph edges atomically", async () => {
156→    const { baseUrl, surreal } = getRuntime();
157→
158→    // Given a draft policy
159→    const user = await createTestUser(baseUrl, "m1-activate");
160→    const workspace = await createTestWorkspace(baseUrl, user);
161→    const adminId = await createTestIdentity(surreal, "admin-1", "human", workspace.workspaceId);
162→
163→    const { policyId } = await createPolicy(surreal, workspace.workspaceId, adminId, {
164→      title: "API Rate Limit Policy",
165→      rules: [{
166→        id: "rate_limit",
167→        condition: { field: "action_spec.action", operator: "eq", value: "api_call" },
168→        effect: "allow",
169→        priority: 10,
170→      }],
171→    });
172→
173→    // When the admin activates the policy
174→    await activatePolicy(surreal, policyId, adminId, workspace.workspaceId);
175→
176→    // Then the policy status is active
177→    const record = await getPolicyRecord(surreal, policyId);
178→    expect(record.status).toBe("active");
179→    expect(record.updated_at).toBeDefined();
180→
181→    // And the governing edge exists (identity -> policy)
182→    const identityRecord = new RecordId("identity", adminId);
