184→      `SELECT ->governing->policy AS policies FROM $identity;`,
185→      { identity: identityRecord },
186→    )) as Array<Array<{ policies: RecordId[] }>>;
187→    const governedPolicies = governingRows[0]?.[0]?.policies ?? [];
188→    const found = governedPolicies.some(p => (p.id as string) === policyId);
189→    expect(found).toBe(true);
190→
