192→    const policyRecord = new RecordId("policy", policyId);
193→    const protectsRows = (await surreal.query(
194→      `SELECT ->protects->workspace AS workspaces FROM $policy;`,
195→      { policy: policyRecord },
196→    )) as Array<Array<{ workspaces: RecordId[] }>>;
197→    const protectedWorkspaces = protectsRows[0]?.[0]?.workspaces ?? [];
