232→    const policyRecord = new RecordId("policy", policyId);
233→    const governingRows = (await surreal.query(
234→      `SELECT * FROM governing WHERE out = $policy;`,
235→      { policy: policyRecord },
236→    )) as Array<Array<unknown>>;
237→    expect(governingRows[0]).toHaveLength(0);
238→
239→    // And the protects edges are removed
240→    const protectsRows = (await surreal.query(
241→      `SELECT * FROM protects WHERE in = $policy;`,
242→      { policy: policyRecord },
243→    )) as Array<Array<unknown>>;
244→    expect(protectsRows[0]).toHaveLength(0);
245→  }, 120_000);
246→});
247→
248→describe("Milestone 1: Graph Relations (US-3)", () => {
